{"file_path": "C:/TASK-105/repo/app/middleware/rbac.py", "content": """"
RBAC decorator — checks the current_user's role against an allowed-roles list.
Must be applied after @require_auth.

Usage:
    @require_auth
    @require_roles("Administrator", "Operations Manager")
    def my_view(): ...
"""
from functools import wraps
from flask import g
from app.errors import ForbiddenError

ROLE_HIERARCHY = {
    "Administrator": 6,
    "Operations Manager": 5,
    "Moderator": 4,
    "Group Leader": 3,
    "Staff": 2,
    "Member": 1,
}


def require_roles(*roles: str):
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            user = g.get("current_user")
            if user is None or user.role not in roles:
                raise ForbiddenError("forbidden", "Insufficient permissions")
            return f(*args, **kwargs)
        return decorated
    return decorator


def require_min_role(min_role: str):
    """Allow any role with hierarchy level >= min_role."""
    min_level = ROLE_HIERARCHY.get(min_role, 0)

    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            user = g.get("current_user")
            if user is None:
                raise ForbiddenError("forbidden", "Insufficient permissions")
            if ROLE_HIERARCHY.get(user.role, 0) < min_level:
                raise ForbiddenError("forbidden", "Insufficient permissions")
            return f(*args, **kwargs)
        return decorated
    return decorator
"}

