        if "settlement_cycle" in data:
            if data["settlement_cycle"] not in SETTLEMENT_CYCLES:
                raise AppError("invalid_cycle", "settlement_cycle must be 'weekly' or 'biweekly'",
                               field="settlement_cycle", status_code=400)
            rule.settlement_cycle = data["settlement_cycle"]

